import{c as i,Q as l,j as a,m as r}from"./chunks/framework.iD28w_5a.js";const s=JSON.parse('{"title":"内核库","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/lib.md","filePath":"document/kernel/lib.md","lastUpdated":1777209094000}'),o={name:"document/kernel/lib.md"};function t(c,e,p,d,n,h){return l(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="内核库" tabindex="-1">内核库 <a class="header-anchor" href="#内核库" aria-label="Permalink to &quot;内核库&quot;">​</a></h1><blockquote><p>里程碑: <code>009_big_kernel_entry</code> <code>012_driver_serial</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>内核自包含的基础库，提供格式化输出（多后端 kprintf）和 freestanding 字符串/内存操作。</p><h2 id="kprintf-多后端架构-kernel-lib-kprintf-hpp-cpp" tabindex="-1">kprintf 多后端架构 (<code>kernel/lib/kprintf.hpp/cpp</code>) <a class="header-anchor" href="#kprintf-多后端架构-kernel-lib-kprintf-hpp-cpp" aria-label="Permalink to &quot;kprintf 多后端架构 (`kernel/lib/kprintf.hpp/cpp`)&quot;">​</a></h2><h3 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h3><ul><li><code>using OutputSink = void(*)(char, void* ctx)</code> — 输出后端回调类型</li><li>最多注册 8 个后端 (serial, console 等)</li><li><code>kprintf/kvprintf</code> 遍历所有 enabled sink 调用</li></ul><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h3><ul><li><code>kprintf_init()</code> — 默认注册 serial sink</li><li><code>kprintf_register_sink(OutputSink, void* ctx)</code> — 注册新后端</li><li><code>kprintf(fmt, ...)</code> / <code>kvprintf(fmt, va_list)</code> — 格式化输出</li><li><code>kpanic(fmt, ...) [[noreturn]]</code> — 格式化输出后 halt</li></ul><h3 id="格式化能力" tabindex="-1">格式化能力 <a class="header-anchor" href="#格式化能力" aria-label="Permalink to &quot;格式化能力&quot;">​</a></h3><ul><li><code>%d %u %x %X %s %p %c %%</code></li><li><code>%08x</code> / <code>%-10s</code> 等宽度和补零修饰</li><li><code>%p</code> 输出 <code>0x</code> + 16 位十六进制</li></ul><h3 id="内部实现-kernel-lib-private-vkprintf-impl-hpp" tabindex="-1">内部实现 (<code>kernel/lib/private/vkprintf_impl.hpp</code>) <a class="header-anchor" href="#内部实现-kernel-lib-private-vkprintf-impl-hpp" aria-label="Permalink to &quot;内部实现 (`kernel/lib/private/vkprintf_impl.hpp`)&quot;">​</a></h3><ul><li><code>fmt_uint(val, base, width, pad, upper, buf, len)</code> — 前补零支持</li></ul><h2 id="字符串-内存操作-kernel-lib-string-hpp-cpp" tabindex="-1">字符串/内存操作 (<code>kernel/lib/string.hpp/cpp</code>) <a class="header-anchor" href="#字符串-内存操作-kernel-lib-string-hpp-cpp" aria-label="Permalink to &quot;字符串/内存操作 (`kernel/lib/string.hpp/cpp`)&quot;">​</a></h2><ul><li><code>memset</code> / <code>memcpy</code> / <code>memmove</code> / <code>memcmp</code></li><li><code>strcmp</code> / <code>strncmp</code> / <code>strlen</code></li></ul><h2 id="原子操作-kernel-lib-atomic-hpp" tabindex="-1">原子操作 (<code>kernel/lib/atomic.hpp</code>) <a class="header-anchor" href="#原子操作-kernel-lib-atomic-hpp" aria-label="Permalink to &quot;原子操作 (`kernel/lib/atomic.hpp`)&quot;">​</a></h2><ul><li>自实现的原子操作，替代 <code>std::atomic</code> 依赖</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/lib/kprintf.hpp/cpp</code></li><li><code>kernel/lib/private/vkprintf_impl.hpp</code></li><li><code>kernel/lib/string.hpp/cpp</code></li><li><code>kernel/lib/atomic.hpp</code></li></ul>',19)])])}const u=i(o,[["render",t]]);export{s as __pageData,u as default};
